package com.example.api.service;

import com.example.api.model.Product;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

import jakarta.annotation.PostConstruct;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicLong;

@Service
public class ProductService {

    private static final Logger logger = LoggerFactory.getLogger(ProductService.class);

    private final Map<Long, Product> productStore = new ConcurrentHashMap<>();
    private final AtomicLong idGenerator = new AtomicLong(1);

    @PostConstruct
    public void init() {
        logger.info("Initializing ProductService with sample data");
        createProduct(new Product(null, "Laptop", "High-performance laptop", 999.99));
        createProduct(new Product(null, "Keyboard", "Mechanical keyboard", 149.99));
        createProduct(new Product(null, "Mouse", "Wireless mouse", 49.99));
        logger.info("ProductService initialized with {} products", productStore.size());
    }

    public List<Product> getAllProducts() {
        logger.info("Retrieving all products");
        List<Product> products = new ArrayList<>(productStore.values());
        logger.info("Retrieved {} products", products.size());
        return products;
    }

    public Optional<Product> getProductById(Long id) {
        logger.info("Retrieving product with id={}", id);
        Optional<Product> product = Optional.ofNullable(productStore.get(id));
        if (product.isPresent()) {
            logger.info("Product found: {}", product.get());
        } else {
            logger.warn("Product with id={} not found", id);
        }
        return product;
    }

    public Product createProduct(Product product) {
        Long id = idGenerator.getAndIncrement();
        product.setId(id);
        productStore.put(id, product);
        logger.info("Created product: {}", product);
        return product;
    }

    public Optional<Product> updateProduct(Long id, Product updatedProduct) {
        logger.info("Updating product with id={}", id);
        if (!productStore.containsKey(id)) {
            logger.warn("Cannot update - product with id={} not found", id);
            return Optional.empty();
        }
        updatedProduct.setId(id);
        productStore.put(id, updatedProduct);
        logger.info("Updated product: {}", updatedProduct);
        return Optional.of(updatedProduct);
    }

    public boolean deleteProduct(Long id) {
        logger.info("Deleting product with id={}", id);
        Product removed = productStore.remove(id);
        if (removed != null) {
            logger.info("Deleted product: {}", removed);
            return true;
        } else {
            logger.warn("Cannot delete - product with id={} not found", id);
            return false;
        }
    }
}

// === controller/ProductController.java ===
package com.example.api.controller;

import com.example.api.model.Product;
import com.example.api.service.ProductService;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.List;
import java.util.Map;

@RestController
@RequestMapping("/api/products")
public class ProductController {

    private static final Logger logger = LoggerFactory.getLogger(ProductController.class);

    private final ProductService productService;

    public ProductController(ProductService productService) {
        this.productService = productService;
        logger.info("ProductController initialized");
    }

    @GetMapping
    public ResponseEntity<List<Product>> getAllProducts() {
        logger.info("GET /api/products - Fetching all products");
        List<Product> products = productService.getAllProducts();
        logger.info("GET /api/products - Returning {} products", products.size());
        return ResponseEntity.ok(products);
    }

    @GetMapping("/{id}")
    public ResponseEntity<Object> getProductById(@PathVariable Long id) {
        logger.info("GET /api/products/{} - Fetching product", id);
        return productService.getProductById(id)
                .<ResponseEntity<Object>>map(product -> {
                    logger.info("GET /api/products/{} - Product found", id);
                    return ResponseEntity.ok(product);
                })
                .orElseGet(() -> {
                    logger.warn("GET /api/products/{} - Product not found", id);
                    return ResponseEntity.status(HttpStatus.NOT_FOUND)
                            .body(Map.of("error", "Product not found", "id", id));
                });
    }

    @PostMapping
    public ResponseEntity<Product> createProduct(@RequestBody Product product) {
        logger.info("POST /api/products - Creating product with name='{}'", product.getName());
        Product created = productService.createProduct(product);
        logger.info("POST /api/products - Product created with id={}", created.getId());
        return ResponseEntity.status(HttpStatus.CREATED).body(created);
    }

    @PutMapping("/{id}")
    public ResponseEntity<Object> updateProduct(@PathVariable Long id, @RequestBody Product product) {
        logger.info("PUT /api/products/{} - Updating product", id);
        return productService.updateProduct(id, product)
                .<ResponseEntity<Object>>map(updated -> {
                    logger.info("PUT /api/products/{} - Product updated successfully", id);
                    return ResponseEntity.ok(updated);
                })
                .orElseGet(() -> {
                    logger.warn("PUT /api/products/{} - Product not found for update", id);
                    return ResponseEntity.status(HttpStatus.NOT_FOUND)
                            .body(Map.of("error", "Product not found", "id", id));
                });
    }

    @DeleteMapping("/{id}")
    public ResponseEntity<Object> deleteProduct(@PathVariable Long id) {
        logger.info("DELETE /api/products/{} - Deleting product", id);
        if (productService.deleteProduct(id)) {
            logger.info("DELETE /api/products/{} - Product deleted successfully", id);
            return ResponseEntity.ok(Map.of("message", "Product deleted successfully", "id", id));
        } else {
            logger.warn("DELETE /api/products/{} - Product not found for deletion", id);
            return ResponseEntity.status(HttpStatus.NOT_FOUND)
                    .body(Map.of("error", "Product not found", "id", id));
        }
    }
}

